verify-allow-failure-behavior.script:
test -f reports/allow-failure-boolean.meta || {
  echo '[ERROR] missing allow-failure-boolean marker'
  exit 1
}
test -f reports/allow-failure-by-exit-code.meta || {
  echo '[ERROR] missing allow-failure-by-exit-code marker'
  exit 1
}
test -f reports/not-allowed-by-exit-code.meta || {
  echo '[ERROR] missing not-allowed-by-exit-code marker'
  exit 1
}
grep -F 'expected_exit_code=7' reports/allow-failure-boolean.meta || {
  echo '[ERROR] allow_failure=true marker mismatch'
  exit 1
}
grep -F 'expected_exit_code=42' reports/allow-failure-by-exit-code.meta || {
  echo '[ERROR] allow_failure.exit_codes accepted marker mismatch'
  exit 1
}
grep -F 'expected_exit_code=9' reports/not-allowed-by-exit-code.meta || {
  echo '[ERROR] rejected exit code marker mismatch'
  exit 1
}
